 1	import React, { FC, Ref, useState } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import {
 5	  Dropdown,
 6	  DropdownItem,
 7	  DropdownList,
 8	  FormGroup,
 9	  MenuToggle,
10	  MenuToggleElement,
11	} from '@patternfly/react-core';
12	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
13	
14	import useNetworkItems from '../../hooks/useNetworkItems';
15	import { NetworkAttachmentDefinitionFormInput } from '../../utils/types';
16	
17	import MissingOperatorsAlert from './components/MissingOperatorsAlert';
18	
19	const NetworkAttachmentDefinitionTypeSelect: FC = () => {
20	  const { t } = useNetworkingTranslation();
21	  const { control } = useFormContext<NetworkAttachmentDefinitionFormInput>();
22	  const [isDropdownOpen, setIsDropdownOpen] = useState<boolean>(false);
23	
24	  const networkTypeItems = useNetworkItems();
25	
26	  const networkTypeTitle = t('Network Type');
27	
28	  return (
29	    <Controller
30	      control={control}
31	      name="networkType"
32	      render={({ field: { onChange, value } }) => (
33	        <FormGroup fieldId="basic-settings-network-type" isRequired label={networkTypeTitle}>
34	          <MissingOperatorsAlert networkTypeItems={networkTypeItems} />
35	          <Dropdown
36	            id="network-type"
37	            isOpen={isDropdownOpen}
38	            onOpenChange={setIsDropdownOpen}
39	            onSelect={() => setIsDropdownOpen(false)}
40	            selected={value}
41	            toggle={(toggleRef: Ref<MenuToggleElement>) => (
42	              <MenuToggle
43	                id="toggle-nads-network-type"
44	                isExpanded={isDropdownOpen}
45	                isFullWidth
46	                onClick={() => setIsDropdownOpen(!isDropdownOpen)}
47	                ref={toggleRef}
48	              >
49	                {networkTypeItems[value] || networkTypeTitle}
50	              </MenuToggle>
51	            )}
52	          >
53	            <DropdownList>
54	              {Object.entries(networkTypeItems).map(([type, label]) => (
55	                <DropdownItem
56	                  key={type}
57	                  onClick={() => {
58	                    onChange(type);
59	                  }}
60	                  value={type}
61	                >
62	                  {label}
63	                </DropdownItem>
64	              ))}
65	            </DropdownList>
66	          </Dropdown>
67	        </FormGroup>
68	      )}
69	      rules={{ required: true }}
70	    />
71	  );
72	};
73	
74	export default NetworkAttachmentDefinitionTypeSelect;

